diff --git a/packages/components/containers/notifications/manager.test.tsx b/packages/components/containers/notifications/manager.test.tsx
new file mode 100644
index 0000000000..4b055226bd
--- /dev/null
+++ b/packages/components/containers/notifications/manager.test.tsx
@@ -0,0 +1,146 @@
+import { useState } from 'react';
+import { renderHook, act } from '@testing-library/react-hooks';
+import { NotificationOptions } from './interfaces';
+
+import createNotificationManager from './manager';
+
+describe('notification manager', () => {
+    describe('deduplication', () => {
+        it('should deduplicate react elements using the provided key', () => {
+            const { result } = renderHook(() => useState<NotificationOptions[]>([]));
+            const [, setState] = result.current;
+
+            const manager = createNotificationManager(setState);
+            act(() => {
+                manager.createNotification({
+                    text: <div>text</div>,
+                    key: 'item1',
+                    type: 'error',
+                });
+                manager.createNotification({
+                    text: <div>text</div>,
+                    key: 'item1',
+                    type: 'error',
+                });
+                manager.createNotification({
+                    text: 'bar',
+                    key: 'item2',
+                    type: 'error',
+                });
+                // Do not deduplicate if key is not provided
+                manager.createNotification({
+                    text: <div>text</div>,
+                    type: 'error',
+                });
+            });
+
+            expect(result.current[0]).toStrictEqual([
+                expect.objectContaining({ text: <div>text</div>, key: 'item1' }),
+                expect.objectContaining({ text: 'bar', key: 'item2' }),
+                expect.objectContaining({ text: <div>text</div> }),
+            ]);
+        });
+    });
+
+    it('should allow to create notifications with raw html text and deduplicate it', () => {
+        const { result } = renderHook(() => useState<NotificationOptions[]>([]));
+        const [, setState] = result.current;
+
+        const manager = createNotificationManager(setState);
+        act(() => {
+            manager.createNotification({
+                text: 'Foo <a href="https://foo.bar">text</a>',
+                type: 'error',
+            });
+            manager.createNotification({
+                text: 'Foo <a href="https://foo.bar">text</a>',
+                type: 'error',
+            });
+        });
+
+        expect(result.current[0]).toHaveLength(1);
+        const notification = result.current[0][0];
+        expect(notification.key).toBe('Foo <a href="https://foo.bar">text</a>');
+        expect(notification.text?.props?.dangerouslySetInnerHTML).toBeDefined();
+        const html = notification.text?.props?.dangerouslySetInnerHTML?.__html ?? '';
+        expect(html).toContain('href="https://foo.bar"');
+        expect(html).toMatch(/noopener/);
+        expect(html).toMatch(/noreferrer/);
+        expect(html).toContain('target="_blank"');
+        expect(html).toContain('>text</a>');
+    });
+
+    it('notification sanitizer only permits safe inline tags', () => {
+        const { result } = renderHook(() => useState<NotificationOptions[]>([]));
+        const [, setState] = result.current;
+
+        const manager = createNotificationManager(setState);
+        act(() => {
+            manager.createNotification({
+                text: '<b>bold</b> <em>italic</em> <strong>strong</strong> <span>span</span> line<br>break <img src="https://tracker.example.com/pixel.gif"> <form action="https://phish.example.com">Submit</form> <p>paragraph</p> <div>block</div> end',
+                type: 'error',
+            });
+        });
+
+        const notification = result.current[0][0];
+        const html = notification.text?.props?.dangerouslySetInnerHTML?.__html ?? '';
+        expect(html).toContain('<b>bold</b>');
+        expect(html).toContain('<em>italic</em>');
+        expect(html).toContain('<strong>strong</strong>');
+        expect(html).toContain('<span>span</span>');
+        expect(html).toMatch(/<br\s*\/?>/i);
+        expect(html).not.toMatch(/<img/i);
+        expect(html).not.toMatch(/<form/i);
+        expect(html).not.toMatch(/<p[\s>]/i);
+        expect(html).not.toMatch(/<div/i);
+    });
+
+    it('rendered html notifications must not contain executable or event-handler markup', () => {
+        const { result } = renderHook(() => useState<NotificationOptions[]>([]));
+        const [, setState] = result.current;
+
+        const manager = createNotificationManager(setState);
+        act(() => {
+            manager.createNotification({
+                text: 'Alert <span onclick="alert(1)" style="color:red" id="xss">trigger</span> and <a href="https://example.com" class="custom">link</a>',
+                type: 'error',
+            });
+        });
+
+        const notification = result.current[0][0];
+        expect(notification.text?.props?.dangerouslySetInnerHTML).toBeDefined();
+        const html = notification.text?.props?.dangerouslySetInnerHTML?.__html ?? '';
+        expect(html).not.toMatch(/onclick/i);
+        expect(html).not.toMatch(/<\s*script/i);
+        expect(html).not.toMatch(/class="/i);
+        expect(html).not.toMatch(/style="/i);
+        expect(html).not.toMatch(/id="xss"/i);
+    });
+
+    it('html content notifications have a minimum display threshold', () => {
+        const { result } = renderHook(() => useState<NotificationOptions[]>([]));
+        const [, setState] = result.current;
+
+        const manager = createNotificationManager(setState);
+        act(() => {
+            manager.createNotification({
+                text: 'Hello <b>world</b>',
+                type: 'error',
+                expiration: 2000,
+            });
+            manager.createNotification({
+                text: 'Check <i>longer</i>',
+                type: 'error',
+                expiration: 8000,
+            });
+        });
+
+        const low = result.current[0][0];
+        expect(low.expiration).toBe(5000);
+        expect(low.disableAutoClose).toBe(true);
+
+        const high = result.current[0][1];
+        expect(high.expiration).toBe(8000);
+        expect(high.disableAutoClose).toBe(true);
+    });
+});
